from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse

app = FastAPI()

@app.middleware("http")
async def rate_limit_middleware(request: Request, call_next):
    tenant_id = request.headers.get("X-Tenant-ID", "anonymous")

    # 1. Check quota before calling Claude
    allowed, reason = check_quota_before_request(tenant_id)
    if not allowed:
        return JSONResponse(
            status_code=429,
            content={"error": reason},
            headers={"Retry-After": "3600"},
        )

    # 2. Check request rate (sliding window: 100 req/min)
    allowed, remaining = is_allowed_sliding(tenant_id, limit=100, window_ms=60_000)
    if not allowed:
        return JSONResponse(
            status_code=429,
            content={"error": "Rate limit exceeded"},
            headers={
                "Retry-After": "60",
                "X-RateLimit-Limit":     "100",
                "X-RateLimit-Remaining": "0",
            },
        )

    response = await call_next(request)
    response.headers["X-RateLimit-Remaining"] = str(remaining)
    return response
